const input = $input.first().json || {};
const clean = (value) => String(value ?? '').trim();
const parseBool = (value, fallback = false) => {
  if (typeof value === 'boolean') return value;
  const s = clean(value).toLowerCase();
  if (['true','1','yes','y'].includes(s)) return true;
  if (['false','0','no','n'].includes(s)) return false;
  return fallback;
};
const nowBkk = $now.setZone('Asia/Bangkok');
const rawMode = clean(input.run_mode).toUpperCase();
const runMode = ['MIDNIGHT','MORNING','EVENING','SATURDAY','MANUAL'].includes(rawMode) ? rawMode : 'MANUAL';
return [{ json: {
  run_mode: runMode,
  request_source: clean(input.request_source || 'manual'),
  send_telegram: parseBool(input.send_telegram, false),
  user_id: clean(input.user_id || '145771888'),
  reason: clean(input.reason || input.message || 'manual_engine_check'),
  active_attempt_id: clean(input.active_attempt_id || ''),
  current_state: clean(input.current_state || '').toUpperCase(),
  force_quest_mode: clean(input.force_quest_mode || '').toUpperCase(),
  message: clean(input.message || ''),
  now_ts: nowBkk.toFormat('yyyy-MM-dd HH:mm:ss'),
  today_date: clean(input.today_date) || nowBkk.toFormat('yyyy-MM-dd'),
  yesterday_date: nowBkk.minus({ days: 1 }).toFormat('yyyy-MM-dd'),
  timezone: 'Asia/Bangkok'
} }];

const nowBkk = $now.setZone('Asia/Bangkok');
const hour = Number(nowBkk.toFormat('H'));
const dayOfWeek = Number(nowBkk.toFormat('c'));
let run_mode;
if (dayOfWeek === 6 && hour >= 9 && hour <= 11) run_mode = 'SATURDAY';
else if (hour < 6) run_mode = 'MIDNIGHT';
else if (hour < 12) run_mode = 'MORNING';
else run_mode = 'EVENING';
return [{ json: {
  run_mode,
  request_source: 'schedule',
  send_telegram: ['MORNING','EVENING','SATURDAY'].includes(run_mode),
  user_id: '145771888',
  reason: `${run_mode.toLowerCase()}_scheduled_run`,
  force_quest_mode: '',
  message: '',
  now_ts: nowBkk.toFormat('yyyy-MM-dd HH:mm:ss'),
  today_date: nowBkk.toFormat('yyyy-MM-dd'),
  yesterday_date: nowBkk.minus({ days: 1 }).toFormat('yyyy-MM-dd'),
  timezone: 'Asia/Bangkok'
} }];

const ctx = $input.first().json || {};
const snapshotRaw = $('Read PROFILE_GAME Snapshot').first().json || {};
const rulesRaw = $('Read GAME_RULES').first().json || {};
const logsRaw = $('Read GAME LOG').first().json || {};
const walletRaw = $('Read WALLET_Monthly Budget Rows').first().json || {};
const taskRaw = $('Read Task List').first().json || {};

const clean = (value) => String(value ?? '').trim();
const upper = (value) => clean(value).toUpperCase();
const parseBool = (value) => {
  if (typeof value === 'boolean') return value;
  const s = clean(value).toLowerCase();
  if (['true', 'yes', '1'].includes(s)) return true;
  if (['false', 'no', '0'].includes(s)) return false;
  return null;
};
const toNumber = (value) => {
  const raw = clean(value)
    .replace(/฿/g, '')
    .replace(/,/g, '')
    .replace(/[()]/g, (m) => (m === '(' ? '-' : ''))
    .replace(/[^\d.-]/g, '');
  if (!raw) return null;
  const n = Number(raw);
  return Number.isFinite(n) ? n : null;
};
const safeJson = (value) => {
  try {
    return JSON.parse(clean(value) || '{}');
  } catch (e) {
    return {};
  }
};
const isoDate = (value) => {
  const s = clean(value);
  if (!s) return '';
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const dtPrefix = s.match(/^(\d{4}-\d{2}-\d{2})/);
  if (dtPrefix) return dtPrefix[1];
  const us = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (us) return `${us[3]}-${String(us[1]).padStart(2, '0')}-${String(us[2]).padStart(2, '0')}`;
  return '';
};
const daysBetween = (fromIso, toIso) => {
  if (!fromIso || !toIso) return null;
  const from = new Date(`${fromIso}T00:00:00Z`);
  const to = new Date(`${toIso}T00:00:00Z`);
  return Math.floor((to - from) / 86400000);
};
const hoursBetween = (fromTs, toTs) => {
  if (!fromTs || !toTs) return null;
  const from = new Date(fromTs.replace(' ', 'T') + 'Z');
  const to = new Date(toTs.replace(' ', 'T') + 'Z');
  if (!from.getTime() || !to.getTime()) return null;
  return Math.floor((to - from) / 3600000);
};
const rowsFromBatch = (raw) => (((raw.valueRanges || [])[0] || {}).values) || [];
const tableFromRows = (rows) => {
  if (!Array.isArray(rows) || !rows.length) return [];
  const header = rows[0].map(clean);
  return rows
    .slice(1)
    .filter((row) => row.some((cell) => clean(cell)))
    .map((row) => {
      const obj = {};
      header.forEach((key, idx) => {
        obj[key] = row[idx] ?? '';
      });
      return obj;
    });
};

const snapshotRows = rowsFromBatch(snapshotRaw);
const snapshot = {};
for (const row of snapshotRows) {
  const leftKey = clean(row[0]);
  const leftVal = clean(row[1]);
  const rightKey = clean(row[2]);
  const rightVal = clean(row[3]);
  if (leftKey) snapshot[leftKey] = leftVal;
  if (rightKey) snapshot[rightKey] = rightVal;
}

const ruleRows = tableFromRows(rowsFromBatch(rulesRaw)).filter((r) => parseBool(r.ACTIVE) !== false);
const logRows = tableFromRows(rowsFromBatch(logsRaw));
const walletRows = tableFromRows(rowsFromBatch(walletRaw));
const taskRows = tableFromRows(rowsFromBatch(taskRaw));

const today = clean(ctx.today_date);
const runMode = upper(ctx.run_mode || 'MANUAL');
const nowTs = clean(ctx.now_ts || $now.setZone('Asia/Bangkok').toFormat('yyyy-MM-dd HH:mm:ss'));
const requestSource = clean(ctx.request_source || 'manual');
const manualActiveAttemptId = Number(clean(ctx.active_attempt_id) || '0') || 0;
const manualCurrentState = upper(ctx.current_state || '');

const snapshotStage = upper(snapshot.PLAYER_STAGE || 'EARLY') || 'EARLY';
const xpTotal = toNumber(snapshot.XP_TOTAL) ?? 0;
const xpGold = toNumber(snapshot.XP_GOLD) ?? 0;
const totalProgress = toNumber(snapshot.TOTAL_PROGRESS) ?? 0;
const balanceThb = toNumber(snapshot.BALANCE_THB) ?? 0;
const currentAttemptFromSnapshot = Number(clean(snapshot.ACTIVE_ATTEMPT_ID) || '0') || 0;
const currentLevelName = clean(snapshot.LEVEL_NAME || '');
const currentLevelScope = clean(snapshot.LEVEL_SCOPE || snapshot.LEVEL_NUMBER || (currentLevelName.match(/\d+/) || [])[0] || '1') || '1';
const levelStartTs = clean(snapshot.LEVEL_START_TS || '');
const debuffName = clean(snapshot.DEBUFF_NAME || '');
const bossName = clean(snapshot.BOSS_NAME || '');
const staleFallback = Number(clean(snapshot.IS_DATA_STALE) || '0') || 0;

const activeStatuses = new Set([
  '⏳ Pending',
  '🔄 In Progress',
  '✋ On Hold',
  '🛑 Delayed',
  '⚠️ Overdue',
  '🔍 Under Review',
]);

const taskRowsNormalized = taskRows
  .map((row, idx) => {
    const taskName = clean(row.Task);
    const startDate = isoDate(row['Start Date']);
    const dueDate = isoDate(row['Due Date']);
    const effectiveDate = dueDate || startDate;
    return {
      row_number: idx + 8,
      task_id: clean(row.TASK_ID),
      task: taskName,
      status: clean(row.Status),
      track: clean(row.Track),
      effective_date: effectiveDate,
      recurring: parseBool(row['Recurring?']) === true,
      frequency: clean(row.Frequency),
    };
  })
  .filter((r) => r.task);

const todayTaskCount = taskRowsNormalized.filter((r) => r.effective_date === today && activeStatuses.has(r.status)).length;
const overdueTaskCount = taskRowsNormalized.filter((r) => r.effective_date && r.effective_date < today && activeStatuses.has(r.status)).length;

const rulesById = new Map(ruleRows.map((r) => [clean(r.ID_NAME), r]));
const findRule = (id) => rulesById.get(id) || ruleRows.find((r) => clean(r.NOTES).includes(id)) || null;
const findScopedRule = (id, levelScope) => {
  const exact = ruleRows.find((r) => clean(r.ID_NAME) === id && clean(r.LEVEL_SCOPE || r.level_scope) === levelScope);
  if (exact) return exact;
  const unscoped = ruleRows.find((r) => clean(r.ID_NAME) === id && !clean(r.LEVEL_SCOPE || r.level_scope));
  if (unscoped) return unscoped;
  return findRule(id);
};

const failThresholdRule = findRule('fail_threshold');
const failPenaltyRule = findRule('fail_penalty_xp_gold');
const stuckRule = findRule('stuck_rule');
const finalLevelRule = findScopedRule('final_level_up', currentLevelScope);

const failThresholdDays = toNumber(failThresholdRule?.TARGET_VALUE) ?? toNumber(failThresholdRule?.VALUE) ?? 5;
const failPenaltyConfig = safeJson(failPenaltyRule?.TARGET_JSON);
const failPenaltyMode = upper(failPenaltyConfig.mode || 'fixed');
const failPenaltyXpGold = Math.abs(toNumber(failPenaltyRule?.VALUE) ?? 0);
const failPenaltyResolved = failPenaltyMode === 'ALL' ? Math.max(0, xpGold) : Math.max(0, failPenaltyXpGold);
const stuckX = toNumber(stuckRule?.VALUE) ?? toNumber(safeJson(stuckRule?.TARGET_JSON).x_amount) ?? 0;
const stuckY = toNumber(stuckRule?.TARGET_VALUE) ?? toNumber(safeJson(stuckRule?.TARGET_JSON).y_days) ?? 0;
const levelUpThreshold =
  toNumber(finalLevelRule?.TARGET_VALUE) ??
  toNumber(finalLevelRule?.VALUE) ??
  toNumber(safeJson(finalLevelRule?.TARGET_JSON).monthly_threshold) ??
  null;

const logs = logRows
  .map((row) => {
    const context = safeJson(row.CONTEXT_JSON);
    const ts = clean(row.TS);
    const dateRef = isoDate(row.DATE_REF) || isoDate(ts);
    return {
      ...row,
      EVENT_TYPE: upper(row.EVENT_TYPE),
      ENTITY_GROUP: upper(row.ENTITY_GROUP),
      STATUS: clean(row.STATUS),
      ATTEMPT_ID: clean(row.ATTEMPT_ID),
      DATE_REF_ISO: dateRef,
      TS_NORM: ts,
      CONTEXT: context,
    };
  })
  .filter((r) => r.EVENT_TYPE || r.ENTITY_GROUP);

logs.sort((a, b) => `${a.DATE_REF_ISO} ${a.TS_NORM}`.localeCompare(`${b.DATE_REF_ISO} ${b.TS_NORM}`));

const onboardingCompleted = logs.some((row) => row.EVENT_TYPE === 'ONBOARDING_COMPLETED');
const structuralEvents = new Set(['ONBOARDING_COMPLETED', 'ATTEMPT_STARTED', 'ATTEMPT_FAILED', 'SPRINT_STARTED', 'SPRINT_ENDED', 'LEVEL_UP_APPROVED', 'THERAPIST_REQUIRED']);
const cutoffBase = new Date(`${today}T00:00:00Z`);
cutoffBase.setUTCDate(cutoffBase.getUTCDate() - 90);
const cutoffIso = cutoffBase.toISOString().slice(0, 10);
const logsForEngine = logs.filter((row) => structuralEvents.has(row.EVENT_TYPE) || (row.DATE_REF_ISO && row.DATE_REF_ISO >= cutoffIso));
const latestOfType = (type) => {
  const target = upper(type);
  for (let i = logsForEngine.length - 1; i >= 0; i -= 1) {
    if (logsForEngine[i].EVENT_TYPE === target) return logsForEngine[i];
  }
  return null;
};
const hasEventToday = (type) => logsForEngine.some((l) => l.EVENT_TYPE === upper(type) && l.DATE_REF_ISO === today);
const hasEventTodayOrPending = (type) => {
  const target = upper(type);
  const pending = gameLogRows.some((row) => String(row[1] || '').toUpperCase() === target && String(row[12] || '') === today);
  return pending || hasEventToday(target);
};

if (!onboardingCompleted) {
  const preGameMessage = 'Игра еще не активирована: онбординг не завершен. Ручные данные в CRM можно заполнять уже сейчас, но они пока считаются pre-game data и не запускают attempt, stage или игровые последствия.';
  return [{ json: {
    ...ctx,
    mode: '',
    user_input: '',
    game_log_rows: [],
    quest_mode: '',
    telegram_text: preGameMessage,
    response_text: preGameMessage,
    engine_payload: {
      run_mode: runMode,
      request_source: requestSource,
      input_current_state: manualCurrentState,
      now_ts: nowTs,
      today_date: today,
      onboarding_completed: false,
      pre_game_mode: true,
      attempt_status: 'NONE',
      active_attempt_id: '',
      stage: 'PRE_GAME',
      stage_xp: 0,
      xp_total: xpTotal,
      xp_gold: xpGold,
      total_progress: totalProgress,
      level_ready: false,
      final_level_up_eligible: false,
      final_level_up_threshold: levelUpThreshold,
      final_level_up_scope: currentLevelScope,
      today_task_count: todayTaskCount,
      overdue_task_count: overdueTaskCount,
      transition_codes: [],
      latest_three_months: [],
    },
    ok: true,
  } }];
}

const lastAttemptStarted = latestOfType('ATTEMPT_STARTED');
const lastAttemptFailed = latestOfType('ATTEMPT_FAILED');
const baseAttemptId = Math.max(currentAttemptFromSnapshot, manualActiveAttemptId);
const maxAttemptId = logsForEngine.reduce((acc, row) => Math.max(acc, Number(row.ATTEMPT_ID || 0) || 0), baseAttemptId);
const hasStarted = !!lastAttemptStarted;
const lastStartTs = lastAttemptStarted ? `${lastAttemptStarted.DATE_REF_ISO} ${lastAttemptStarted.TS_NORM}` : '';
const lastFailTs = lastAttemptFailed ? `${lastAttemptFailed.DATE_REF_ISO} ${lastAttemptFailed.TS_NORM}` : '';
let attemptActive = hasStarted ? (!lastAttemptFailed || lastStartTs > lastFailTs) : baseAttemptId > 0;
let currentAttemptId = attemptActive ? Number(lastAttemptStarted?.ATTEMPT_ID || maxAttemptId || baseAttemptId || 1) || 1 : maxAttemptId;

const attemptActivityEvents = new Set(['ONBOARDING_COMPLETED', 'ATTEMPT_STARTED', 'RULE_CREATED', 'RULE_UPDATED', 'GOLD_GAINED', 'GOLD_LOST', 'HABIT_DONE', 'HABIT_SKIPPED', 'TASK_CREATED', 'TASK_UPDATED', 'TASK_STATUS_CHANGED', 'TASK_COMPLETED', 'DAY_PLAN_UPDATED', 'GOAL_DECOMPOSED', 'BELIEF_RECORDED', 'THERAPY_DISCUSSION', 'THERAPY_SESSION_COMPLETED', 'TARGET_REVIEWED', 'THERAPY_REFRAME_COMPLETED', 'LEVEL_UP_INTERVIEW_STARTED', 'LEVEL_UP_APPROVED', 'LEVEL_UP_HELD']);
const meaningfulEvents = logsForEngine.filter((row) => attemptActivityEvents.has(row.EVENT_TYPE));
const latestMeaningful = meaningfulEvents.length ? meaningfulEvents[meaningfulEvents.length - 1] : null;
const lastActivityDate = latestMeaningful?.DATE_REF_ISO || '';
const silentDays = lastActivityDate ? (daysBetween(lastActivityDate, today) ?? staleFallback) : staleFallback;

const goalActionWindowStart = (days) => {
  if (!days || !today) return '';
  const base = new Date(`${today}T00:00:00Z`);
  base.setUTCDate(base.getUTCDate() - (days - 1));
  return base.toISOString().slice(0, 10);
};

const activityAfterLastFail = meaningfulEvents.filter((row) => !lastAttemptFailed || `${row.DATE_REF_ISO} ${row.TS_NORM}` > lastFailTs);
const newestActivityAfterFail = activityAfterLastFail.length ? activityAfterLastFail[activityAfterLastFail.length - 1] : null;

const transitionCodes = [];
const gameLogRows = [];
const bossRules = ruleRows.filter((row) => upper(row.RULE_GROUP) === 'BOSS');
const sprintLengthRule = findRule('sprint_length');
const sprintLengthDays = toNumber(sprintLengthRule?.TARGET_VALUE) ?? toNumber(sprintLengthRule?.VALUE) ?? null;
const goalRule = findRule('current_level_goal');
const goalRuleJson = safeJson(goalRule?.TARGET_JSON);
const explicitHorizonDate = isoDate(goalRuleJson.horizon_date || goalRule?.TARGET_VALUE || '');
const horizonDays = toNumber(goalRuleJson.horizon_days) ?? toNumber(goalRule?.VALUE) ?? null;
const computedHorizonDate = explicitHorizonDate || (horizonDays && levelStartTs ? (() => { const d = new Date(`${isoDate(levelStartTs)}T00:00:00Z`); d.setUTCDate(d.getUTCDate() + Number(horizonDays)); return d.toISOString().slice(0, 10); })() : '');
const hashSeed = (value) => String(value || '').split('').reduce((acc, ch) => ((acc * 31) + ch.charCodeAt(0)) % 2147483647, 7);
const chooseBossRule = (seed) => {
  if (!bossRules.length) return null;
  return bossRules[hashSeed(seed) % bossRules.length] || bossRules[0];
};
const logRow = ({
  event_type,
  entity_group,
  entity_id = '',
  entity_name = '',
  track = '',
  status = '',
  value = '',
  resource_type = '',
  delta = '',
  period = '',
  date_ref = today,
  stage_at_time = snapshotStage,
  level_at_time = currentLevelName || '1',
  attempt_id = String(currentAttemptId || ''),
  context_json = '',
  comment = '',
}) => [nowTs, event_type, 'ENGINE', entity_group, entity_id, entity_name, track, status, value, resource_type, delta, period, date_ref, stage_at_time, level_at_time, attempt_id, context_json, comment];


const sprintLifecycleAllowed = attemptActive || !!newestActivityAfterFail;
const latestSprintStarted = latestOfType('SPRINT_STARTED');
const latestSprintEnded = latestOfType('SPRINT_ENDED');
const sprintStartDate = latestSprintStarted?.DATE_REF_ISO || '';
const sprintIsOpen = !!latestSprintStarted && (!latestSprintEnded || `${latestSprintStarted.DATE_REF_ISO} ${latestSprintStarted.TS_NORM}` > `${latestSprintEnded.DATE_REF_ISO} ${latestSprintEnded.TS_NORM}`);
const startSprint = (status = 'STARTED', context = {}) => {
  transitionCodes.push('SPRINT_STARTED');
  gameLogRows.push(logRow({
    event_type: 'SPRINT_STARTED',
    entity_group: 'SPRINT',
    entity_id: `${currentAttemptId || 1}:${today}`,
    entity_name: 'Sprint',
    status,
    value: String(sprintLengthDays || ''),
    resource_type: 'DAY',
    period: 'SPRINT',
    stage_at_time: snapshotStage,
    context_json: JSON.stringify({ sprint_length_days: sprintLengthDays, ...context }),
    comment: 'ENGINE открыл новый спринт',
  }));
  const selectedBoss = chooseBossRule(`${currentAttemptId || 1}|${today}`);
  if (selectedBoss) {
    transitionCodes.push('BOSS_ACTIVATED');
    gameLogRows.push(logRow({
      event_type: 'BOSS_ACTIVATED',
      entity_group: 'BOSS',
      entity_id: clean(selectedBoss.ID_NAME),
      entity_name: clean(selectedBoss.RPG_NAME || selectedBoss.ID_NAME),
      status: 'ACTIVATED',
      value: clean(selectedBoss.VALUE),
      resource_type: clean(selectedBoss.RESOURCE_TYPE || 'XP_Gold'),
      stage_at_time: snapshotStage,
      context_json: JSON.stringify({ sprint_length_days: sprintLengthDays, boss_rule_id: clean(selectedBoss.ID_NAME) }),
      comment: 'На спринт активирован текущий босс',
    }));
  }
};
if (sprintLengthDays && sprintLifecycleAllowed && !hasEventToday('SPRINT_STARTED') && !latestSprintStarted) {
  startSprint('STARTED', { reason: 'engine_bootstrap' });
} else if (sprintLengthDays && sprintLifecycleAllowed && sprintIsOpen && sprintStartDate) {
  const sprintAge = daysBetween(sprintStartDate, today);
  if (sprintAge !== null && sprintAge >= sprintLengthDays && !hasEventToday('SPRINT_ENDED')) {
    transitionCodes.push('SPRINT_ENDED');
    gameLogRows.push(logRow({
      event_type: 'SPRINT_ENDED',
      entity_group: 'SPRINT',
      entity_id: `${currentAttemptId || 1}:${sprintStartDate}`,
      entity_name: 'Sprint',
      status: 'ENDED',
      value: String(sprintAge),
      resource_type: 'DAY',
      period: 'SPRINT',
      stage_at_time: snapshotStage,
      context_json: JSON.stringify({ sprint_started_at: sprintStartDate, sprint_length_days: sprintLengthDays }),
      comment: 'ENGINE закрыл спринт по длине',
    }));
    startSprint('RESTARTED', { previous_start_date: sprintStartDate });
  }
}

let failHappenedNow = false;
if (attemptActive && silentDays >= failThresholdDays && !hasEventToday('ATTEMPT_FAILED')) {
  failHappenedNow = true;
  const failAttemptId = String(currentAttemptId || 1);
  const failPenaltyAlreadyLogged = logsForEngine.some((row) => row.EVENT_TYPE === 'GOLD_LOST' && row.ENTITY_GROUP === 'ATTEMPT' && clean(row.ENTITY_ID) === failAttemptId && (clean(row.STATUS) === 'BURNED' || clean(row.CONTEXT?.reason) === 'ATTEMPT_FAILED'));
  transitionCodes.push('ATTEMPT_FAILED');
  gameLogRows.push(logRow({
    event_type: 'ATTEMPT_FAILED',
    entity_group: 'ATTEMPT',
    entity_id: failAttemptId,
    entity_name: `Attempt ${failAttemptId}`,
    status: 'FAILED',
    value: String(failThresholdDays),
    resource_type: 'DAYS',
    delta: '',
    period: 'DAY',
    stage_at_time: snapshotStage,
    context_json: JSON.stringify({ silent_days: silentDays, fail_threshold_days: failThresholdDays, xp_gold_penalty: failPenaltyResolved, fail_penalty_mode: failPenaltyMode }),
    comment: '5 дней тишины: attempt failed',
  }));
  if (failPenaltyResolved > 0 && !failPenaltyAlreadyLogged) {
    transitionCodes.push('GOLD_LOST');
    gameLogRows.push(logRow({
      event_type: 'GOLD_LOST',
      entity_group: 'ATTEMPT',
      entity_id: failAttemptId,
      entity_name: `Attempt ${failAttemptId}`,
      status: 'BURNED',
      value: String(xpGold),
      resource_type: 'XP_GOLD',
      delta: String(-Math.abs(failPenaltyResolved)),
      period: 'FAIL',
      stage_at_time: snapshotStage,
      context_json: JSON.stringify({ reason: 'ATTEMPT_FAILED', fail_threshold_days: failThresholdDays, fail_penalty_mode: failPenaltyMode, fail_penalty_value: failPenaltyResolved }),
      comment: `XP_Gold сгорел при провале attempt #${failAttemptId}`,
    }));
  }
  attemptActive = false;
}

const historicalFails = logsForEngine.filter((row) => row.EVENT_TYPE === 'ATTEMPT_FAILED').length + (failHappenedNow ? 1 : 0);
let needsTherapist = historicalFails >= 5;
if (needsTherapist && !hasEventTodayOrPending('THERAPIST_REQUIRED')) {
  transitionCodes.push('THERAPIST_REQUIRED');
  gameLogRows.push(logRow({
    event_type: 'THERAPIST_REQUIRED',
    entity_group: 'THERAPY',
    entity_id: 'reframe_after_5_fails',
    entity_name: 'Therapist Reframe Required',
    status: 'REQUIRED',
    value: String(historicalFails),
    resource_type: 'FAILS',
    context_json: JSON.stringify({ fail_count: historicalFails }),
    comment: 'После 5 fail требуется reframe через therapist',
  }));
}

let newAttemptStartedNow = false;
if (!attemptActive && newestActivityAfterFail) {
  currentAttemptId = (Number(currentAttemptId || 0) || 0) + 1;
  newAttemptStartedNow = true;
  transitionCodes.push('ATTEMPT_STARTED');
  gameLogRows.push(logRow({
    event_type: 'ATTEMPT_STARTED',
    entity_group: 'ATTEMPT',
    entity_id: String(currentAttemptId),
    entity_name: `Attempt ${currentAttemptId}`,
    status: 'ACTIVE',
    stage_at_time: 'EARLY',
    attempt_id: String(currentAttemptId),
    context_json: JSON.stringify({ started_from: 'activity_return', xp_total_at_start: xpTotal }),
    comment: 'Новая попытка стартовала после возвращения игрока',
  }));
  attemptActive = true;
}

let xpAtAttemptStart = 0;
if (newAttemptStartedNow) xpAtAttemptStart = xpTotal;
else if (lastAttemptStarted && Number(lastAttemptStarted.ATTEMPT_ID || 0) === Number(currentAttemptId || 0)) xpAtAttemptStart = toNumber(lastAttemptStarted.CONTEXT?.xp_total_at_start) ?? 0;

const stageXp = Math.max(0, xpTotal - xpAtAttemptStart);
let derivedStage = 'EARLY';
if (!attemptActive || failHappenedNow) derivedStage = 'EARLY';
else if (stageXp >= 3500) derivedStage = 'LATE';
else if (stageXp >= 500) derivedStage = 'MID';

if (derivedStage !== snapshotStage && !hasEventToday('STAGE_CHANGED')) {
  transitionCodes.push('STAGE_CHANGED');
  gameLogRows.push(logRow({
    event_type: 'STAGE_CHANGED',
    entity_group: 'STAGE',
    entity_id: derivedStage,
    entity_name: derivedStage,
    status: derivedStage,
