let stuckTimeDetected = false;
let silentHoursSinceActivity = null;
if (attemptActive && !failHappenedNow && latestMeaningful) {
  const latestTs = `${latestMeaningful.DATE_REF_ISO} ${latestMeaningful.TS_NORM}`;
  silentHoursSinceActivity = hoursBetween(latestTs, nowTs);
