}

let stuckDetected = false;
let moneyNetWindow = null;
let goalActionsCount = 0;
if (stuckX > 0 && stuckY > 0) {
  const windowStart = goalActionWindowStart(stuckY);
  const goalActionEvents = meaningfulEvents.filter((row) => ['TASK', 'KPI'].includes(row.ENTITY_GROUP) && row.DATE_REF_ISO && row.DATE_REF_ISO >= windowStart);
  goalActionsCount = goalActionEvents.length;
  const walletWindow = walletRows.filter((row) => {
    const d = isoDate(row.DATE);
    const currency = upper(row.CURRENCY || '');
    return d && d >= windowStart && d <= today && (!currency || currency.includes('THB') || currency.includes('БАТ'));
  });
  moneyNetWindow = walletWindow.reduce((sum, row) => sum + (toNumber(row.SIGNED_AMOUNT) ?? 0), 0);
  stuckDetected = goalActionsCount > 0 && moneyNetWindow < stuckX;
  if (stuckDetected && !hasEventToday('STUCK_TRIGGERED')) {
    transitionCodes.push('STUCK_TRIGGERED');
    gameLogRows.push(logRow({
      event_type: 'STUCK_TRIGGERED',
