}


const treasureHorizonReachedToday = hasEventToday('TREASURE_HORIZON_REACHED');
const treasureHorizonAlreadyLogged = !!(computedHorizonDate && logs.some((row) => row.EVENT_TYPE === 'TREASURE_HORIZON_REACHED' && clean(row.ENTITY_ID) === clean(goalRule?.ID_NAME || 'current_level_goal') && clean(row.CONTEXT?.horizon_date) === computedHorizonDate));
const levelApprovedCurrent = logsForEngine.some((row) => row.EVENT_TYPE === 'LEVEL_UP_APPROVED' && (!levelStartTs || `${row.DATE_REF_ISO} ${row.TS_NORM}` >= levelStartTs));
