}

let finalLevelEligible = false;
let latestThreeMonths = [];
if (levelUpThreshold != null) {
  const monthSums = {};
  for (const row of walletRows) {
    const monthKey = clean(row.MONTH_KEY);
    const currency = upper(row.CURRENCY || '');
    if (!monthKey || (currency && !currency.includes('THB') && !currency.includes('БАТ'))) continue;
    monthSums[monthKey] = (monthSums[monthKey] || 0) + (toNumber(row.SIGNED_AMOUNT) ?? 0);
  }
  latestThreeMonths = Object.keys(monthSums).sort().slice(-3).map((key) => ({ key, value: monthSums[key] }));
  finalLevelEligible = latestThreeMonths.length === 3 && latestThreeMonths.every((item) => item.value >= levelUpThreshold);
}

const todayEvents = meaningfulEvents.filter((r) => r.DATE_REF_ISO === today);
const energySignalsToday = new Set();
for (const row of todayEvents) {
  const token = `${clean(row.ENTITY_ID)} ${clean(row.ENTITY_NAME)} ${clean(row.COMMENT)}`.toLowerCase();
  if (/sleep|сон/.test(token)) energySignalsToday.add('sleep');
  if (/food|meal|еда|завтрак|обед|ужин/.test(token)) energySignalsToday.add('food');
  if (/water|вода/.test(token)) energySignalsToday.add('water');
}

const ruleActionEvents = new Set(['HABIT_DONE', 'HABIT_SKIPPED', 'TASK_CREATED', 'TASK_UPDATED', 'TASK_STATUS_CHANGED', 'TASK_COMPLETED', 'DAY_PLAN_UPDATED', 'GOAL_DECOMPOSED', 'GOLD_GAINED', 'GOLD_LOST', 'BELIEF_RECORDED', 'THERAPY_DISCUSSION', 'THERAPY_SESSION_COMPLETED', 'RULE_CREATED', 'RULE_UPDATED', 'TARGET_REVIEWED']);
