else if (energySignalsToday.size >= 2 && ruleActionsToday.length > 0) consistencyStatus = 'FULFILLED';
else if (energySignalsToday.size >= 1 || ruleActionsToday.length > 0) consistencyStatus = 'MIN_OK';
else if (attemptActive && silentDays >= Math.max(1, failThresholdDays - 2)) consistencyStatus = 'AT_RISK';
else if (attemptActive && silentDays <= 1) consistencyStatus = 'ON_TRACK';

let commitStatus = 'UNOBSERVED';
if (failHappenedNow) commitStatus = 'BROKEN';
else if (consistencyStatus === 'FULFILLED') commitStatus = 'KEPT';
else if (ruleActionsToday.length > 0 || energySignalsToday.size > 0) commitStatus = 'PARTIAL';
else if (attemptActive && silentDays >= Math.max(1, failThresholdDays - 2)) commitStatus = 'FRAGILE';
else if (attemptActive) commitStatus = 'ACTIVE';

if (runMode === 'MIDNIGHT' && !hasEventToday('CONSISTENCY_CHECKED')) {
  transitionCodes.push('CONSISTENCY_CHECKED');
  gameLogRows.push(logRow({
