}

let questMode = upper(ctx.force_quest_mode || '');
if (!questMode) {
  if (!needsTherapist && runMode === 'MORNING') questMode = 'PLANNER';
  else if (!needsTherapist && runMode === 'EVENING') questMode = 'EVENING_REVIEW';
}
if (!['PLANNER', 'EVENING_REVIEW'].includes(questMode)) questMode = '';

let recommendedNextWorkflow = 'NONE';
if (needsTherapist) recommendedNextWorkflow = 'THERAPIST';
else if (questMode) recommendedNextWorkflow = 'QUEST_ARCHITECT';

const messageParts = [];
