if (ruleActionsToday.length || energySignalsToday.size) messageParts.push(`Сигналы дня: actions ${ruleActionsToday.length}, energy ${energySignalsToday.size}/3.`);
if (failHappenedNow) messageParts.push(`Провал attempt: ${silentDays} дней тишины. Сгорает XP_Gold по правилу.`);
else if (attemptActive && silentDays >= Math.max(1, failThresholdDays - 2)) messageParts.push(`Консистентность под риском: ${silentDays} дней без записанной активности.`);
if (stuckDetected) messageParts.push(`STUCK: действий по цели ${goalActionsCount}, money net за окно ${stuckY}д = ${moneyNetWindow}.`);
