const spec = $('Generate Week Sheets').item.json;
const q = (sheet) => `'${sheet.replace(/'/g, "''")}'`;
const data = [];
if (spec.type === 'daily') {
  data.push({ range: `${q(spec.name)}!B3`, values: [[spec.name]] });
  data.push({ range: `${q(spec.name)}!B6`, values: [[spec.iso]] });
  return [{ json: { ...spec, data } }];
}
const sheet = spec.name;
data.push({ range: `${q(sheet)}!B3`, values: [[spec.name]] });
data.push({ range: `${q(sheet)}!B6`, values: [[spec.iso]] });
data.push({ range: `${q(sheet)}!B7`, values: [['=WEEKDAY(B6,1)']] });
const habitBlocks = [
  { lookupCol: 'F', startCol: 'H', endCol: 'N', startRow: 4, endRow: 11 },
  { lookupCol: 'R', startCol: 'T', endCol: 'Z', startRow: 4, endRow: 10 },
];
for (const block of habitBlocks) {
  for (let row = block.startRow; row <= block.endRow; row++) {
    const vals = [];
    for (let day = 0; day < 7; day++) {
      vals.push(`=IFERROR(VLOOKUP($${block.lookupCol}${row}, INDIRECT("'" & TEXT($B$6+${day}, "yy.mm.dd") & "'!$B$18:$D$32"), 3, 0), FALSE)`);
    }
    data.push({ range: `${q(sheet)}!${block.startCol}${row}:${block.endCol}${row}`, values: [vals] });
  }
}
const groups = [
  { taskCol: 'G', checkCol: 'H', day: 0 },
  { taskCol: 'M', checkCol: 'P', day: 1 },
  { taskCol: 'S', checkCol: 'T', day: 2 },
  { taskCol: 'Y', checkCol: 'AB', day: 3 },
  { taskCol: 'AE', checkCol: 'AF', day: 4 },
  { taskCol: 'AI', checkCol: 'AJ', day: 5 },
  { taskCol: 'AM', checkCol: 'AN', day: 6 },
];
for (const group of groups) {
  const taskValues = [];
  const checkValues = [];
  for (let weeklyRow = 26; weeklyRow <= 43; weeklyRow++) {
    const dailyRow = 15 + (weeklyRow - 26);
    taskValues.push([`=IFERROR(INDIRECT("'" & TEXT($B$6+${group.day}, "yy.mm.dd") & "'!G${dailyRow}"), "")`]);
    checkValues.push([`=IFERROR(INDIRECT("'" & TEXT($B$6+${group.day}, "yy.mm.dd") & "'!H${dailyRow}"), FALSE)`]);
  }
  data.push({ range: `${q(sheet)}!${group.taskCol}26:${group.taskCol}43`, values: taskValues });
  data.push({ range: `${q(sheet)}!${group.checkCol}26:${group.checkCol}43`, values: checkValues });
}
return [{ json: { ...spec, data } }];

